class Solution:
    def maximumProduct(self, nums):
        # Independent single-pass tracking of the three largest and two smallest.
        import math
        max1 = max2 = max3 = -math.inf
        min1 = min2 = math.inf
        for x in nums:
            if x > max1:
                max3, max2, max1 = max2, max1, x
            elif x > max2:
                max3, max2 = max2, x
            elif x > max3:
                max3 = x
            if x < min1:
                min2, min1 = min1, x
            elif x < min2:
                min2 = x
        return int(max(max1 * max2 * max3, min1 * min2 * max1))

